**D) `doGenerate` method** -- SIMPLIFIED compared to Luma (no polling, no image editing):
```ts
async doGenerate({
  prompt,
  n,
  size,
  aspectRatio,
  seed,
  providerOptions,
  headers,
  abortSignal,
  files,
  mask,
}: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
  Awaited<ReturnType<ImageModelV3['doGenerate']>>
> {
  const warnings: Array<SharedV3Warning> = [];

  // PixelArt does not support files/mask (no image editing)
  if (files != null && files.length > 0) {
    warnings.push({
      type: 'unsupported',
      feature: 'files',
      details: 'PixelArt does not support image editing via files.',
    });
  }
  if (mask != null) {
    warnings.push({
      type: 'unsupported',
      feature: 'mask',
      details: 'PixelArt does not support mask-based inpainting.',
    });
  }

  // aspectRatio is not supported, only size
  if (aspectRatio != null) {
    warnings.push({
      type: 'unsupported',
      feature: 'aspectRatio',
      details: 'PixelArt does not support aspectRatio. Use size instead.',
    });
  }

  const pixelArtOptions = await parseProviderOptions({
    provider: 'pixelart',
    providerOptions,
    schema: pixelArtImageModelOptionsSchema,
  });

  const { style, pixelDensity, ...otherOptions } = pixelArtOptions ?? {};

  const currentDate = this.config._internal?.currentDate?.() ?? new Date();
  const fullHeaders = combineHeaders(this.config.headers(), headers);

  const { value: response, responseHeaders } = await postJsonToApi({
    url: `${this.config.baseURL}/generate`,
    headers: fullHeaders,
    body: {
      prompt,
      model: this.modelId,
      ...(n != null ? { n } : {}),
      ...(size != null ? { size } : {}),
      ...(seed != null ? { seed } : {}),
      ...(style != null ? { style } : {}),
      ...(pixelDensity != null ? { pixel_density: pixelDensity } : {}),
      ...otherOptions,
    },
    abortSignal,
    fetch: this.config.fetch,
    failedResponseHandler: createJsonErrorResponseHandler({
      errorSchema: pixelArtErrorSchema,
      errorToMessage: (error) => error.message ?? 'Unknown error',
    }),
    successfulResponseHandler: createJsonResponseHandler(
      pixelArtResponseSchema,
    ),
  });

  return {
    images: response.images,  // base64 strings
    warnings,
    response: {
      modelId: this.modelId,
      timestamp: currentDate,
      headers: responseHeaders,
    },
  };
}
```

